68: ContextImpl::ContextImpl(Stats::Scope& scope, const Envoy::Ssl::ContextConfig& config,
69:                          Server::Configuration::CommonFactoryContext& factory_context,
70:                          Ssl::ContextAdditionalInitFunc additional_init,
71:                          absl::Status& creation_status)
72:     : scope_(scope), stats_(generateSslStats(scope)), factory_context_(factory_context),
73:       tls_max_version_(config.maxProtocolVersion()),
74:       stat_name_set_(scope.symbolTable().makeSet("TransportSockets::Tls")),
75:       unknown_ssl_cipher_(stat_name_set_->add("unknown_ssl_cipher")),
76:       unknown_ssl_curve_(stat_name_set_->add("unknown_ssl_curve")),
77:       unknown_ssl_algorithm_(stat_name_set_->add("unknown_ssl_algorithm")),
78:       unknown_ssl_version_(stat_name_set_->add("unknown_ssl_version")),
79:       ssl_ciphers_(stat_name_set_->add("ssl.ciphers")),
80:       ssl_versions_(stat_name_set_->add("ssl.versions")),
81:       ssl_curves_(stat_name_set_->add("ssl.curves")),
82:       ssl_sigalgs_(stat_name_set_->add("ssl.sigalgs")), capabilities_(config.capabilities()),
83:       tls_keylog_local_(config.tlsKeyLogLocal()), tls_keylog_remote_(config.tlsKeyLogRemote()) {
84: 
85:   auto cert_validator_name = getCertValidatorName(config.certificateValidationContext());
86:   auto cert_validator_factory =
87:       Registry::FactoryRegistry<CertValidatorFactory>::getFactory(cert_validator_name);
88: 
89:   if (!cert_validator_factory) {
90:     creation_status = absl::InvalidArgumentError(
91:         absl::StrCat("Failed to get certificate validator factory for ", cert_validator_name));
92:     return;
93:   }
94: 
95:   cert_validator_ = cert_validator_factory->createCertValidator(
96:       config.certificateValidationContext(), stats_, factory_context_);
97: 
98:   const auto tls_certificates = config.tlsCertificates();
99:   tls_contexts_.resize(std::max(static_cast<size_t>(1), tls_certificates.size()));
100: 
101:   std::vector<SSL_CTX*> ssl_contexts(tls_contexts_.size());
102:   for (size_t i = 0; i < tls_contexts_.size(); i++) {
103:     auto& ctx = tls_contexts_[i];
104:     ctx.ssl_ctx_.reset(SSL_CTX_new(TLS_method()));
105:     ssl_contexts[i] = ctx.ssl_ctx_.get();
106: 
107:     int rc = SSL_CTX_set_app_data(ctx.ssl_ctx_.get(), this);
108:     RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
109: 
110:     rc = SSL_CTX_set_min_proto_version(ctx.ssl_ctx_.get(), config.minProtocolVersion());
111:     RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
112: 
113:     rc = SSL_CTX_set_max_proto_version(ctx.ssl_ctx_.get(), config.maxProtocolVersion());
114:     RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
115: 
116:     if (!capabilities_.provides_ciphers_and_curves &&
117:         !SSL_CTX_set_strict_cipher_list(ctx.ssl_ctx_.get(), config.cipherSuites().c_str())) {
118:       // Break up a set of ciphers into each individual cipher and try them each individually in
119:       // order to attempt to log which specific one failed. Example of config.cipherSuites():
120:       // "-ALL:[ECDHE-ECDSA-AES128-GCM-SHA256|ECDHE-ECDSA-CHACHA20-POLY1305]:ECDHE-ECDSA-AES128-SHA".
121:       //
122:       // "-" is both an operator when in the leading position of a token (-ALL: don't allow this
123:       // cipher), and the common separator in names (ECDHE-ECDSA-AES128-GCM-SHA256). Don't split on
124:       // it because it will separate pieces of the same cipher. When it is a leading character, it
125:       // is removed below.
126:       std::vector<absl::string_view> ciphers =
127:           StringUtil::splitToken(config.cipherSuites(), ":+![|]", false);
128:       std::vector<std::string> bad_ciphers;
129:       for (const auto& cipher : ciphers) {
130:         std::string cipher_str(cipher);
131: 
132:         if (absl::StartsWith(cipher_str, "-")) {
133:           cipher_str.erase(cipher_str.begin());
